// Interface — the abstraction
public interface IntegracaoClient {
    void enviar(DadosIntegracao dados);
}

// Implementations resolved at runtime via CDI
public class MoodleClient implements IntegracaoClient {
    @Override
    public void enviar(DadosIntegracao dados) {
        // REST call to Moodle
    }
}

public class LdapClient implements IntegracaoClient {
    @Override
    public void enviar(DadosIntegracao dados) {
        // LDAP operation
    }
}

// Caller — doesn't know which implementation
public class IntegracaoBusiness {
    @Inject
    private IntegracaoClient client;

    public void processar(Long idMatricula) {
        client.enviar(buildDados(idMatricula));
    }
}
